var e=[{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이해를 바라지는 않는다.`,JPN:`理解を求めてはいない。`,ENG:`I do not wish for understanding.`,TWN:`我不奢望有人理解。`},stage:{bg:`CHURCH`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`신앙을 부르짖는 자들은, 그냥 거기 그대로 있으면 돼.`,JPN:`信仰を叫ぶ者たちは、そのままそこにいれば十分。`,ENG:`Those who cry out for faith shall stay as they are.`,TWN:`那些打著信仰旗幟的人，只需要隔岸觀火。`},stage:{bg:`CHURCH`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`그들의 눈으로 본 아름다운 세상을 내게 속삭여 줄 테니까.`,JPN:`彼らの目で見たキレイな世界を私に囁いてくれるだろうから。`,ENG:`For they shall whisper to me about the beautiful world of which they have seen with their own eyes.`,TWN:`因為他們眼睛所見的美麗世界會向我私語。`},stage:{bg:`CHURCH`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:null,text:{KOREA:`결국 교단 내에서 누군가는 해야 할 일이다.`,JPN:`結局教団の誰かはやるべきことだ。`,ENG:`For someone in the Order needs take this responsibility.`,TWN:`教團內終究必須有人來做這件事。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:null,text:{KOREA:`그러니 신앙을 부르짖는 자들은, 그냥 거기 그대로 있으면 돼.`,JPN:`だから、信仰を叫ぶ者たちは、そのままそこにいれば十分。`,ENG:`So those who cry out for faith shall stay as they are.`,TWN:`那些打著信仰旗幟的人，只需要隔岸觀火。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:null,text:{KOREA:`신성을 모욕하고 세상의 증오를 받아 마땅한 일은 내게 맡기소서.`,JPN:`神聖を侮辱し、世界に憎悪されるべき仕事は私にお任せください。`,ENG:`For I shall take upon myself the hatred of this world, and perform such acts that insult the gods.`,TWN:`會玷汙神聖，遭世界憎恨的事，就交給我吧。`},stage:{bg:`COUNTERSIDE_BUILDING`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`거리에서 죽었어야 할 내 목숨을 위대한 정적이 건져 올리셨으니.`,JPN:`街で死んでいたはずの私の命を、偉大な静寂がお救いになった。`,ENG:`My life should have died on the streets, but the Great Silence rescued me.`,TWN:`是偉大的寂靜在街上將瀕死的我給救回來的。`},stage:{bg:`HARMONY_05`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`이제 그 뜻대로 쓰임 받을지어다.`,JPN:`御心のままにお使いになるだろう。`,ENG:`Use me to accomplish your will.`,TWN:`現在我要按著她的意思而為。`},stage:{bg:`HARMONY_05`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SENA_HARMONY_NULL_NULL`,text:{KOREA:`지휘자님? 예하께서 방문하셨어요.`,JPN:`マエストロ？　猊下がお見えになりました。`,ENG:`Maestra Nequitia? Eminence has arrived.`,TWN:`指揮家？主教來訪。`},stage:{bg:`LABORATORY_02`,slots:{L:null,C:{char_id:`SENA_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`SENA_HARMONY_NULL_NULL`,text:{KOREA:`심문관들을 대동하지는 않았는데…… 어떻게 할까요?`,JPN:`尋問官は一緒ではありませんが……どういたしましょうか。`,ENG:`She is not accompanied by the inquisition... What should we do?`,TWN:`沒有審訊官同行……該怎麼辦呢？`},stage:{bg:`LABORATORY_02`,slots:{L:null,C:{char_id:`SENA_HARMONY_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NULL`,text:{KOREA:`오늘은 음색이 유독 아름답더니 반가운 손님이 오시기 때문이군요.`,JPN:`今日はひときわ音色が美しいと思ったら、懐かしいお客様が訪ねてくださったのですね。`,ENG:`Music is especially beautiful, for today, we have a special guest.`,TWN:`怪不得今天的音色特別悅耳，原來是有貴賓造訪。`},stage:{bg:`LABORATORY_02`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NULL`,text:{KOREA:`예하께서 바깥 바람을 오래 쐬시게 하는 건 예의가 아니지요.`,JPN:`猊下を長らく外の空気にお晒しすることは礼儀ではありません。`,ENG:`It is not polite to make her wait for such a long time.`,TWN:`讓主教在外面乾等不是待客之道，`},stage:{bg:`LABORATORY_02`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NULL`,text:{KOREA:`안으로 모시세요. 제가 직접 응대하겠습니다.`,JPN:`中へご案内しなさい。私がじきに接待しましょう。`,ENG:`Let her in. I shall take care of it personally.`,TWN:`快請她進來，我親自來接待她。`},stage:{bg:`LABORATORY_02`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L36_1`,type:`dialog`,speaker:`MORS_SHADOW_ARMOR_NULL`,text:{KOREA:`……마에스트로, 대답을 전하러 왔다.`,JPN:`……マエストロ、答えを伝えに来た。`,ENG:`...Maestra, I have arrived with an answer.`,TWN:`……指揮家，我是來回答你的。`},stage:{bg:`LABORATORY_02`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L37_1`,type:`dialog`,speaker:`CONDUCT_HARMONY_NULL_NULL`,text:{KOREA:`앉으시죠. 미사가 아니면 골방에 틀어박혀 사는지라 대접할 건 없습니다만.`,JPN:`どうぞお座りください。ミサでなければ部屋に閉じこもっているばかりですので、おもてなしできるようなものはありませんが。`,ENG:`Please, have a seat. Since I seldom leave the small room of mine except for Mass, I am afraid I do not have much to offer.`,TWN:`請坐。沒有彌撒的時候，我都待在房裡，所以沒什麼可以招待的。`},stage:{bg:`LABORATORY_02`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};